SELECT region, product, sales,
       SUM(sales) OVER (PARTITION BY region ORDER BY sold_at) AS running_total
FROM sales_log;

const sales = [{region: 'US', product: 'A', amount: 1000}, {region: 'US', product: 'B', amount: 500}];
const partition = {};
sales.forEach(s => {
  if (!partition[s.region]) partition[s.region] = [];
  partition[s.region].push(s);
});
console.log(partition);

from itertools import groupby
sales = [{'region': 'US', 'product': 'A'}, {'region': 'US', 'product': 'B'}, {'region': 'EU', 'product': 'C'}]
partition = {k: list(g) for k, g in groupby(sales, key=lambda x: x['region'])}

